        let mut row = Vec::with_capacity(n - seg_len + 1);
        for i in 0..=(n - seg_len) {
            let g1 = st[k-1][i];
            let g2 = st[k-1][i + step];
            let g_val = gcd(g1, g2);
            row.push(g_val);
        }
        st.push(row);
