struct SparseTable {
    table: Vec<Vec<i64>>,
    log: Vec<usize>,
}

impl SparseTable {
    fn new(arr: &[i64]) -> Self {
        let n = arr.len();
        let mut log = vec![0; n + 1];
        for i in 2..=n {
            log[i] = log[i >> 1] + 1;
        }
        let max_log = log[n] + 1;
        let mut table = vec![vec![0; n]; max_log];
        table[0] = arr.to_vec();
        for i in 1..max_log {
            let step = 1 << (i - 1);
            for j in 0..=n - (1 << i) {
                table[i][j] = gcd(table[i - 1][j], table[i - 1][j + step]);
            }
        }
        SparseTable { table, log }
    }

    fn query(&self, l: usize, r: usize) -> i64 {
        if l > r {
            return 0;
        }
        let len = r - l + 1;
        let k = self.log[len];
        gcd(self.table[k][l], self.table[k][r - (1 << k) + 1])
    }
}

fn f(x: i64, st: &SparseTable, n: usize, max_c: i64) -> bool {
    if x >= n as i64 {
        return true;
    }
    let l = x + 1;
    if l > n as i64 {
        return true;
    }
    let l_usize = l as usize;
    if l_usize > n {
        return true;
    }
    let mut active_rights = Vec::new();
    for i in 0..=n - l_usize {
        let j = i + l_usize - 1;
        let g = st.query(i, j);
        if g >= 2 {
            active_rights.push(j);
