use std::mem::swap;

fn gcd(mut a: i64, mut b: i64) -> i64 {
    if a == 0 {
        return b.abs();
    }
    if b == 0 {
        return a.abs();
    }
    while b != 0 {
        a %= b;
        swap(&mut a, &mut b);
    }
    a.abs()
}

fn solve(nums: Vec<i64>, maxC: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }
    let non_ones = nums.iter().filter(|&&x| x != 1).count() as i64;
    if maxC >= non_ones {
        return 0;
    }

    let nn = n;
    let mut log_table = vec![0; nn + 1];
    for i in 2..=nn {
        log_table[i] = log_table[i >> 1] + 1;
    }
    let k_max = log_table[nn] as usize;

    let mut st = vec![vec![0; nn]; k_max + 1];
    for (i, &num) in nums.iter().enumerate().take(nn) {
        st[0][i] = num;
    }

    for k in 1..=k_max {
        let shift = 1 << (k - 1);
        for i in 0..=(nn - (1 << k)) {
            st[k][i] = gcd(st[k - 1][i], st[k - 1][i + shift]);
        }
    }

    let can_achieve = |X: i64| -> bool {
        let L = X + 1;
        if L > nn as i64 {
            return true;
        }
        let L_usize = L as usize;
        let k = log_table[L_usize];
        let step = 1 << k;

        let mut stable_intervals = Vec::new();

        for i in 0..=(nn - L_usize) {
            let left_gcd = st[k][i];
            let right_idx = i + L_usize - step;
            let right_gcd = st[k][right_idx];
            let g = gcd(left_gcd, right_gcd);
            if g >= 2 {
                stable_intervals.push((i, i + L_usize - 1));
            }
        }

        if stable_intervals.is_empty() {
            return true;
        }

        stable_intervals.sort_by_key(|&(_, end)| end);
        let mut breaks = 0;
        let mut last_break = -1;
        for &(start, end) in &stable_intervals {
            if start as i64 > last_break {
                breaks += 1;
                last_break = end as i64;
                if breaks > maxC {
                    break;
                }
            }
        }

        breaks <= maxC
    };

    let mut low = 1;
    let mut high = nn as i64;
    let mut ans = high;
    while low <= high {
        let mid = (low + high) >> 1;
        if can_achieve(mid) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    ans
}
